#include<bits/stdc++.h>  //万能头文件
using namespace std;
int x, y;
string a;    //定义变量
int main() {
	cin >> a; //输入字符串
	a=" "+a;  //这样输入的第一个字符就在下标1上了
	for (int i = 1; i < a.size(); i++) {
		if (a[i] == 'A') {
			if (i % 2 == 1) {
				x++;  //统计字符串的奇数下标上$A$的数量
			} else {
				y++;   //统计字符串的偶数下标上$A$的数量
			}

		}
	}
	if ((x + y) % 2 == 1) { //判断A的数量是不是2的倍数
		cout << "-1";
		return 0;
	}
	if(x>y) cout << (x - y) / 2; //输出结果
    else cout << (y - x) / 2;  //输出结果
	return 0;  //结束
}
